sp_widget.client_script:
api.controller=function($scope,$location,$rootScope,spModal,$uibModal,spUtil,amb,$timeout,$log, $sce) {
  /* widget controller */
  var c = this;
	var CONST_DISABLED_ANCHOR_CLASS = "dtech-a-disabled";
	var CONST_ENABLED_ANCHOR_CLASS = "dtech-a-enabled";

	main();
	function main(){
		// convert warnings to HTML $sce.trustAsHtml("<b>Some Text<b>")
alert(c.data.memberTableRoleCompareRoleMembers);
		c.data.syncRoleMembersAndMemberTableRole = $sce.trustAsHtml(c.data.syncRoleMembersAndMemberTableRole);
		c.data.memberTableRoleCompareRoleMembers = $sce.trustAsHtml(c.data.memberTableRoleCompareRoleMembers);
alert("after - " + c.data.memberTableRoleCompareRoleMembers);
		c.data.currentProperty = undefined;
		c.currentTab = null;
		c.countSelected=null;
		c.allGroupsSelected = false;
		// if no category set, loading them all, 
		// if Groups Management, load group management
		if(!c.data.category || 
			 c.data.category=="" || 
			 c.data.category == "Groups Management"){
			c.data.groupProperties=	_loadGroupSettings();	
			_setAllValidatingProperties(false);
		}
	}

	// ***********************************************************
	// START - Gropus Management Category - properties
	// ***********************************************************	
	// This is used for all references properities that use groups.
	// currently only the Groups Management categetory

	// *******************************************
	// START WIDGET CONTROL FUNCTIONS
	// *******************************************
	function _getClass(enabled){
		var className;
		className = CONST_DISABLED_ANCHOR_CLASS;
		if(enabled){
			className = CONST_ENABLED_ANCHOR_CLASS;
		}
		return className; 
	}	
	$scope.changeSelectedProperty = function(property){
		_changeSelectedProperty(property);
	}
	$scope.selectCount = function(countSelected){
		_selectCount(countSelected);
	};
	$scope.onChange_uses_groups_for_roles = function(property){
		_updateIsDirty();
	}

	$scope.changeSelectedGroup = function (property){
		$scope.validateGroup(property);
		_updateIsDirty();		
	}

	$scope.isCountSelected = function(countIcon){
		var countIconSelected = countIcon == c.countSelected;
		return countIconSelected;
	}	

	function _replacePropertyReturned(){
		_clearValidatingFlag($scope.data.replaceProperty);
		$scope.data.properties = _findAndReplaceProperty($scope.data.properties, $scope.data.replaceProperty);
		_setAllValidatingProperties(false);
		// move the selected property and refresh the property data to what is returned from the server
		_changeSelectedProperty($scope.data.replaceProperty);
	}
	// *******************************************
	// END WIDGET CONTROL FUNCTIONS
	// *******************************************


	// *******************************************
	// START SYNC ALL
	// *******************************************
	$scope.syncAll = function(){
		_syncAll();
	}
	$scope.validateGroup = function(property){
		$scope.data.submitting=true;
		property.validating = true;
		// post back to check group
		$scope.data.validateGroup=true;
		$scope.data.groupProperty = property;
		spUtil.update($scope).then(function(){
			// turned off after timer below - see _clearValidatingFlag function
			//$scope.data.submitting=false;
			$scope.data.validateGroup=false;
			_replacePropertyReturned();
		});
	}
	// *******************************************
	// END SYNC ALL
	// *******************************************

	// *******************************************
	// START ADD GROUP MENU OPTION
	// *******************************************
	$scope.allowAddGroup = function(property){
		var canAddGroup = !c.data.submitting &&
				(!property.value ||
				 property.value=='undefined' ||
				 property.value.value=='');
		return canAddGroup;
	}
	$scope.classAllowAddGroup = function(property){
		var canAddGroup = $scope.allowAddGroup(property);
		return _getClass(canAddGroup);
	}
	$scope.addGroup = function(property){
		c.data.addProperty = property;
		var shared = { 
			fields: {
				sys_id: {
					value: -1, 
					displayValue: "", 
					sys_mandatory: false, 
					mandatory: false, 
					placeholder: "", 
					readonly: false
				}
			}
		};		
		spModal.open({
			title: c.data.addGroup,
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: "sys_user_group",
				sys_id: -1,
				hideRelatedLists: true,
				// STRY0115843
				omitHeader: false,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: shared,
			size: 'lg',
			buttons: [''],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		}).then(function() {
			// DFCT0011220 - receive ID back from modal
			if(!c.data.addProperty.value){
				c.data.addProperty.value = {};
			}
			// TODO - the line below does not seem to update the picker
			c.data.addProperty.value.value = shared.fields.sys_id.value;
		});
	}

	$scope.$on("$destroy", function() {
		unregister_ui_action_complete_triggered();
	});

	// *******************************************
	// END ADD GROUP MENU OPTION
	// *******************************************

	// *******************************************
	// START EDIT GROUP MENU OPTION
	// *******************************************
	$scope.allowEditGroup = function(property){
		var canEditGroup = !c.data.submitting &&
				property.value &&
				property.value!='undefined' &&
				property.value.value!='';
		return canEditGroup;
	}

	$scope.classAllowEditGroup = function(property){
		var canEditGroup = $scope.allowEditGroup(property);
		return _getClass(canEditGroup);
	}

	$scope.editGroup = function(property){
		spModal.open({
			title: c.data.editGroup,
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: "sys_user_group",
				sys_id: property.value.value,
				hideRelatedLists: false,
				// STRY0115843
				omitHeader: false,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			size: 'lg',
			buttons: [],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});
	};
	// *******************************************
	// END EDIT GROUP MENU OPTION
	// *******************************************

	// *******************************************
	// START SYNC GROUP MENU OPTION
	// *******************************************
	$scope.allowSyncGroup = function(property){
		var canSyncGroup = !c.data.submitting &&
				property.value &&
				property.value!='undefined' &&
				property.value.value!='';
		return canSyncGroup;
	}

	$scope.classAllowSyncGroup = function(property){
		var canSyncGroup = $scope.allowSyncGroup(property);
		return _getClass(canSyncGroup);
	}
	// *******************************************
	// END SYNC GROUP MENU OPTION
	// *******************************************

	// *******************************************
	// START ENABLE GROUP ROLE MANAGEMENT
	// *******************************************
	$scope.is_property_uses_groups_for_roles = function(property){
		return _is_property_uses_groups_for_roles(property);
	}

	function _is_property_uses_groups_for_roles(property){
		var isPropertyUsesGroupsForRoles=false;
		if(property){
			isPropertyUsesGroupsForRoles = property.name=='x_153465_discovert.uses_groups_for_roles';	
		}
		return isPropertyUsesGroupsForRoles;		
	}

	$scope.aGroupSelectedUsesGroupsForRolesNotSet = function(property){
		var showWarning = false;
		showWarning = c.atLeastOneGroupSelected && property.value!='true' && property.value!=true;
		return showWarning;
	}

	$scope.allowUsesGroupsForRoles = function(property){
		var allowChangeUsesGroupsForRoles;
		allowChangeUsesGroupsForRoles = c.allGroupsSelected ||
			property.value== 'true' || property.value==true;
		return allowChangeUsesGroupsForRoles;
	}
	// *******************************************
	// END ENABLE GROUP ROLE MANAGEMENT
	// *******************************************

	// *********************************
	// START GROUP SELECTED
	// *********************************
	$scope.isGroupSelected = function(property){
		var isGroupSelected = property.validation && property.validation.groupSelected;
		return isGroupSelected;
	}

	// this is slightly different than is group selected b/c validation needs to be complete
	// for us to want to show the warning
	$scope.showGroupNotSelected = function(property){
		var showGroupSelected = property.validation && !property.validation.groupSelected;
		return showGroupSelected;
	}
	// *********************************
	// END GROUP SELECTED
	// *********************************

	// *********************************
	// START GROUP HAS ROLE
	// *********************************
	// this is slightly different than is group missing role b/c validation needs to be complete
	// for us to want to show the warning
	$scope.showGroupMissingRole = function(property){
		var showGroupMissingRole = property.validating==false &&
				property.validation && 
				property.validation.groupSelected  &&
				!property.validation.groupHasRole;
		return showGroupMissingRole;
	}
	$scope.allowFixGroupHasRole = function(property){
		var isGroupSelected = $scope.isGroupSelected(property);
		var groupHasRole = property.validation && property.validation.groupHasRole;
		var allowFixRole = !c.data.submitting && 
				isGroupSelected && !groupHasRole;
		return allowFixRole;
	}	
	$scope.classFixGroupHasRole = function(property){
		var allowFixRole = $scope.allowFixGroupHasRole(property);
		return _getClass(allowFixRole);		
	}
	$scope.onAddGroupToRole = function(property){
		$scope.data.submitting=true;
		$scope.data.addRoleToGroup=true;
		$scope.data.groupProperty = property;
		spUtil.update($scope).then(function(){
			$scope.data.submitting=false;
			c.data.addRoleToGroup = false;
		});		
	}
	// *********************************
	// END GROUP HAS ROLE
	// *********************************

	// *********************************
	// START MOVE USERS TO GROUP
	// *********************************
	$scope.showMigrateExplicitUsersToGroup = function(property){
		var showMigrateMessage = property.validation.explicitRoleCount > 0;
		return showMigrateMessage;
	}
	$scope.allowMigrateExplicitUsersToGroup = function(property){
		var isGroupSelected = $scope.isGroupSelected(property);
		var allowFixRole = !c.data.submitting && 
				isGroupSelected && 
				property.validation.explicitRoleCount > 0;
		return allowFixRole;
	}	
	$scope.classFixMigrateExplicitUsersToGroup = function(property){
		var allowFixMigrate = $scope.allowMigrateExplicitUsersToGroup(property);
		return _getClass(allowFixMigrate);
	}
	$scope.migrateRoleUsersToGroup = function(property){
		$scope.data.submitting=true;
		$scope.data.migrateRoleUsersToGroup=true;
		$scope.data.groupProperty = property;
		spUtil.update($scope).then(function(){
// TODO - update this to match other calls to get results back in property
			$scope.data.submitting=false;
			c.data.migrateRoleUsersToGroup = false;
		});				
	}	

	// *********************************
	// END MOVE USERS TO GROUP
	// *********************************

	// ***********************************************
	// START SYNC ROLE TO ORGANIZATIONAL MEMBERS TABLE
	// ***********************************************
	$scope.showRoleSyncWarn = function(property){
		var showRoleSync = c.data.currentGroupMemberCount!=c.data.currentRoleMemberTableRoleCount;
		return showRoleSync;
	}
	$scope.classRoleSync = function(property){
		var allowFix = $scope.allowRoleSync(property)
		return _getClass(allowFix);
	}
	$scope.allowRoleSync = function(property){
		var allowFixRole = !c.data.submitting;
		return allowFixRole;
	}	
	$scope.syncRoleMemberTable=function(property){
		$scope.data.submitting=true;
		$scope.data.syncMembersInMemberTableWithRole=true;
		$scope.data.groupProperty = property;
		spUtil.update($scope).then(function(){
			$scope.data.submitting=false;
			c.data.syncMembersInMemberTableWithRole = false;
			_replacePropertyReturned();
		});

	}
	// ***********************************************
	// END SYNC ROLE TO ORGANIZATIONAL MEMBERS TABLE
	// ***********************************************

	// ***********************************************************
	// END - Gropus Management Category - properties
	// ***********************************************************

	// ***********************************************************
	// START - used for all properties and categories
	// ***********************************************************
	// STRY0122687 - fix active tab not working issue
	$scope.setActiveTab = function( activeTab ){
		c.currentTab = activeTab;
	};

	$scope.getActiveTab = function(){
		return c.currentTab;
	};

	$scope.isActiveTab = function( tabName, index ){
		var activeTab = $scope.getActiveTab();
		return ( activeTab === tabName || ( activeTab === null && index === 0 ) );
	};

	// reset all properies to the original value
	$scope.onCancel = function(property){

		spModal.confirm(c.data.cancelChangesWillBeLost).then(function(confirmed) {
			if (confirmed) {
				// resetting didn't load the names back into the group
				// for now reload from system by calling validate all again
				/*
						c.data.properties.forEach(function(property) {
							if(typeof property.value == "object"){
								property.value.value = property.originalValue;
							} else {
								property.value = property.originalValue;
							}
						});
				*/
				_reloadData();
			}
		});
	}

	$scope.onSubmit = function() {
		$scope.data.submitting = true;
		$scope.data.properties = c.data.properties;
		$scope.data.saveProperties=true;
		// post back with loaded flase to reload data
		$scope.data.loaded=false;
		spUtil.update($scope).then(function(){
			$scope.data.saveProperties=false;
			$scope.data.submitting = false;
			// reload client
			main();
			c.data.isDirty=false;

		});

	};
	// ***********************************************************
	// END - used for all properties and categories
	// ***********************************************************

	// ***********************************************************
	// START - Gropus Management Category - properties
	// ***********************************************************	
	// This is used for all references properities that use groups.
	// currently only the Groups Management categetory
	function _reloadData() {
		$scope.data.submitting=true;
		// post back with loaded flase to reload data
		$scope.data.loaded=false;
		spUtil.update($scope).then(function(){
			// turned off after timer below - see _setAllValidatingProperties function
			$scope.data.submitting=false;
			// reload client
			main()
			c.data.isDirty=false;
		});
	}

	function _selectCount(countSelected){
		c.countSelected = countSelected;
		_loadMemberData(countSelected);		
	}	

	function _changeSelectedProperty(property){
		c.data.currentProperty = property;
		loadKnowledgeArticleWidget(property);

		if(_is_property_uses_groups_for_roles(property)){
			c.currentTab = 'KnowledgeBaseArticle';			
		} else {
			c.currentTab = 'Counts';			
			_setCountsAndWarningFlags(property);
			c.data.dataTables = [];
			_selectCount(c.data.groupMembersIcon);
		}
	}

	function _setCountsAndWarningFlags(property){
		c.data.currentValidationCompleted = false;
		c.data.currentGroupMemberCount = 0; 
		c.data.currentExplicitRoleCount = 0; 
		c.data.currentRoleMemberTableRoleCount = 0;
		// set error and warning flags for selected property
		c.data.currentValidated = false;

		if(property.validation){
			c.data.currentValidationCompleted = true;
		}

		// set validation flag
		if(c.data.currentValidationCompleted){
			// set current counts
			c.data.currentGroupMemberCount = property.validation.groupMemberCount;
			c.data.currentExplicitRoleCount = property.validation.explicitRoleCount;
			c.data.currentRoleMemberTableRoleCount = property.validation.roleMemberTableRoleCount;
		}

	}
	function loadKnowledgeArticleWidget(property){
		$scope.data.widgetInstanceKBArticles = [];
		$scope.data.widgetInstanceKBRelatedArticles = [];
		$scope.data.getKnowledge=true;
		$scope.data.groupProperty = property;
		spUtil.update($scope).then(function(data){
			$scope.data.widgetInstanceKBArticles = data.widgetInstanceKBArticles;
			$scope.data.widgetInstanceKBRelatedArticles = data.widgetInstanceKBRelatedArticles;
			$scope.data.getKnowledge=false;
		});
	}

	function loadKnowledgeRelatedArticleWidget(property){
		c.data.widgetInstanceKBRelatedArticles = [];

		var widget_name = "tasker_knowledge_list_widget_template";
		var widget_parameters = {};


//		var widget_name = "kb-list-widget-template";
//		var widget_name = "kb_related_articles";
//		var widget_name = "kb-list-widget-template";
//		var widget_parameters = {
//			options:{"source_id": "587d1212db8d99501e1792c5d496192e"}
//		};
//	var widget_parameters = {
//				"source_id": c.data.dtech_knowledged_base_id,
//				"sysparm_article": property.KBArticle
//		};
		spUtil.get(widget_name, widget_parameters).then(function(response) {
			var widgetKBRelatedArticles = response;
//			widgetKBRelatedArticles.options = {
//				"sysparm_article": property.KBArticle
//			};
			c.data.widgetInstanceKBRelatedArticles.push(widgetKBRelatedArticles);
		});
/*

		var widget_name = "discovertasker-widget-data-table";
		var widget_parameters = {};
		widget_parameters.table = 'kb_2_kb';
//		widget_parameters.sys_id="";
		widget_parameters.filter = "^kb_knowledge.number=" + property.KBArticle;
		widget_parameters.bifold=true;
		widget_parameters.open_new_in_modal=true;
		widget_parameters.open_row_details_in_modal=true;
		widget_parameters.enable_filter=true;
		spUtil.get(widget_name, widget_parameters).then(function(response) {
			c.data.widgetInstanceKBRelatedArticles.push(response);
		});
*/		
	}	
		function _syncAll() {
		$scope.data.submitting=true;
		// post back to validate all groups
		$scope.data.syncAll=true;
		spUtil.update($scope).then(function(){
			$scope.data.submitting=false;
			$scope.data.syncAll=false;
			_allGroupValidationCompleted();
		});
	}

	function _validateAllGroups() {
		_setAllValidatingProperties(true);
		$scope.data.submitting=true;
		// post back to validate all groups
		$scope.data.validateAllGroups=true;
		spUtil.update($scope).then(function(){
			// turned off after timer below - see _setAllValidatingProperties function
			//$scope.data.submitting=false;
			$scope.data.validateAllGroups=false;
			_allGroupValidationCompleted();
		});
	}
	function _allGroupValidationCompleted(){
		$timeout(function(){
			// - return from server sets validating to false
			 _setAllValidatingProperties(false);
		},1000);
	}
	function _loadGroupSettings(){
		var groupProperties = {};
		// set up group controls
		groupProperties.query='active=true';
		groupProperties.displayFields='name,manager,email';
		groupProperties.displayField='name';
		groupProperties.valueField='sys_id';
		groupProperties.searchFields = 'name,manager,email';		
		groupProperties.table = "sys_user_group";
		// set up group controls
		return groupProperties;
	}
	function _loadMemberData(countSelected){
		c.data.dataTables = [];
		var widget_name = "discovertasker-widget-data-table"
		var widget_parameters = {};

		switch (countSelected){
			case c.data.groupMembersIcon:
				widget_parameters.table = 'sys_user_grmember';
				widget_parameters.filter= '^group=' + c.data.currentProperty.value.value;
				break;
				// Using e here b/c explicit and role members use same icon right now
				// this may change with better udnerstanding of Shawn's latest layouts
			case c.data.explicitRoleUsersIcon:
				widget_parameters.table = 'sys_user_has_role';
				widget_parameters.filter= '^role.name=' + c.data.currentProperty.roleName +
					'^inherited=false';
				break;
			case c.data.roleMembersIcon:
				widget_parameters.table = 'sys_user_has_role';
				widget_parameters.filter= '^role.name=' + c.data.currentProperty.roleName;
				break;				
			case c.data.memberTableRoleIcon:
				widget_parameters.table = 'x_153465_discovert_discover_office_members';
				widget_parameters.filter= '^' + c.data.currentProperty.memberTableFieldName + '=true';
				// todo figure out if/how to do distinct list
				break;				
		}
		if(widget_parameters.table){
			widget_parameters.bifold=true;
			widget_parameters.open_new_in_modal=true;
			widget_parameters.open_row_details_in_modal=true;
			widget_parameters.enable_filter=true;
			spUtil.get(widget_name, widget_parameters).then(function(response) {
				c.data.dataTables.push(response);
			});
		}
	}	
	function _setAllValidatingProperties(value){
		var allGroupsSet = true;
		var atLeastOneGroupSet = false;
		for (var i = 0; i < c.data.properties.length; i++) {
			var property = c.data.properties[i];
			// if no current property, then set to first property found
			// wait until validating is finished which is when value is false
			if(!c.data.currentProperty && value == false){
				_changeSelectedProperty(property);
			}
			if (property.name != "x_153465_discovert.uses_groups_for_roles") {
				property.validating=value;
				if(!property.value || 
					 !property.value.value || 
					 property.value.value==''){
					allGroupsSet=false;
				} else {
					atLeastOneGroupSet=true;
				}
			}
		}
		c.allGroupsSelected=allGroupsSet;
		c.atLeastOneGroupSelected=atLeastOneGroupSet;
		$scope.data.submitting=false;
	}
	function _clearValidatingFlag(property){
		$timeout(function(){
			// - return from server sets validating to false
			property.validating = false;
			$scope.data.submitting=false;
		},1000);
	}

	function _findAndReplaceProperty(properties, replaceProperty) {
		for (var i = 0; i < properties.length; i++) {
			var property = properties[i];
			if (property.name == replaceProperty.name) {
				properties[i] = replaceProperty;
				break;
			}
		}
		return properties;
	}
	function _updateIsDirty(){
		var isDirty=false;
		// loop through properties check original value vs current
		// set isDirty flag
		c.data.properties.forEach(function(property) {
			if(typeof property.value == "object"){
				if(property.originalValue != property.value.value){
					if(property.originalValue==null){
						if(property.value!=null && property.value.value != ""){
							isDirty=true;
						}
					} else {
						isDirty=true;						
					}
				}
			} else {
				if(property.originalValue != property.value){
					isDirty=true;
				}				
			}
		});

		c.data.isDirty=isDirty;
	}
	// ***********************************************************
	// END - Gropus Management Category - Functions
	// ***********************************************************

};

sp_widget.css:
progress {
  margin: 4px;
}

progress:indeterminate {
  width:100%;
  height:20px;
}
#group_properties{
  flex-grow: .4 0 500px;
}
#group_information{
  flex-grow: .6;
}

.dtech-a-disabled {
  white-space: nowrap;
  cursor: not-allowed;
  opacity:.5;
}
.dtech-a-enabled {
  white-space: nowrap;
  cursor: pointer;
}
.dtech-panel-bottom{
  margin-bottom:5px;
}
.dtech-properties-groupsmanagement-widget-container{
  max-height: -webkit-fill-available; 
}

.dtech-group-properties-information-tabcontent{
  display:flex;
  flex-direction:column;
  flex-grow:1;
  margin:5px;
  overflow:auto;
}
.dtech-kb-container{
  display:flex;
  overflow:auto;
}
.dtech-kb-column1{
  display:flex;
  flex-direction:column;
  flex-grow: .5;
  overflow:auto;
}
.dtech-kb-column2{
  display:flex;
  flex-direction:column;
  flex-grow: .5;
  overflow:auto;
}
/* only in this widget used to remove grey background */
.circle-error {
  border: 1px solid gray;
  color: danger;
  border-radius: 50%;
  margin: 9px 5px 5px 5px;
  width: 12px;
  height: 12px; 
  display: inline-block;
}
.dtech-btn-icon {
  background:transparent;
}
/* used to create space around buttons */
.dtech-margin-all-10 {
  margin:10px;
}

.dtech-margin-left-10{
  margin-left:10px;
}
/* used for warning messages */
.dtech-property-warning-message {
  padding:3px;
  background-color:#f5f5f5;
}
/* used to lower tabs */
.dtech-pad-top-5 {
  padding-top:5px;
}
.dtech-pad-left-5 {
  padding-left:5px;
}
/* this class is used to set focus.  
It is the same style as the servicenow btn:focus 
TODO - We may want to move into global class*/

/* font to make the name bolder than the descripiton */
.dtech-font-property-name{
  padding-top:10px;
  color: rgba(0, 0, 0, 1);
  font-size: 14px;
  font-weight: 600;
  text-align: left;  
}
/* font to make the count number bolder and align left */
.dtech-font-count {
  color: rgba(0, 0, 0, 1);
  font-size: 16px;
  font-weight: 600;
  text-align: left;
} 

/* sets disabled count */
.dtech-font-count:disabled {
  color: rgba(175, 188, 194, 1);
} 

/* sets the font for the text of the count */
.dtech-font-description {
  color: rgba(117, 117, 117, 1);
  font-size: 14px;
  font-weight: 400;
} 

/* this comes over from portal filter */
.dtech-border-none {
  border:none;
}

.dtech-dropdown-header {
  /* color: #3A3F51; */
  font-size: 14px;
  font-weight: 500;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added padding */
  padding: 10px 20px;
}

/* Bootstrap 3.3.6 default: .dropdown-menu > li > a:hover, .dropdown-menu > li > a:focus { */
/* this overrides the defaults for dropdown items for the filter menu*/
.dropdown-menu > li > ul > li > a:hover, .dropdown-menu > li > ul > li > a:focus {
  text-decoration: none;
  color: #2f3342;
  background-color: #f5f5f5;
}

/* this sets the color for the count badge for filter items*/
.badge {
  background-color: $banner-count-bg;
  color: $banner-count-text;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added height for badge */
  height: 20px;
}
/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-flex-space-15px {
  width: 15px;
}
.dtech-dropdown-menu-align-right{
  right: 0;
  left: auto;
}

.dtech-filter-menu {
  /*
  2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Added box-shadow
  Note using rgba, (Red Green Blue Alpha) that controls the opacity or transparency 
  that follows the same percentage scheme: 0% represents absolute transparency and 100% represents absolute opacity 
  */
  box-shadow: 0 6px 12px rgba(0, 0, 0, .25); /* yields: box-shadow: 0 6px 12px rgb(0 0 0 / 25%); */
  right: 45px; /* aligns with right side of the count control*/
  left: auto; /* allows width to grow as needed */


}

.dtech-margin-right-5px {
  margin-right: 5px;
}

.dtech-inline-start {
  padding-left: 15px;
}

.dtech-pad-top-5px {
  padding: 5px 0;
}

.dtech-scrollable-menu {
  height: auto;
  /* 2.7.0 | 2021-08-19 | mmcc | STRY0107445 - Filter Menu – CSS Adjustments – Menu Sizing; Changed max-height, was 500 */
  max-height: 700px;
  overflow-x: hidden;
}

.dtech-subMenu {
  list-style-type: none;
  padding: 2px 0;
}

.dtech-subMenu-item {
  color: #3A3F51;
  font-size: 14px;
  font-weight: normal;
}

