 *  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
// Below is a list ot things still to do before shipping
// ******************************************************
// review all todo's in the code and update them
// sync all member table is completed
// need to put statistics about rows changed somewhere
// sync all update sycn all of member table to process table one time
//		- REVIEW AND ADD ERROR MESSAGES FROM FUNCTIONS
//    - TRAP ADD CLICK FROM ADD GROUP AND LOAD GROUP ADDED INTO GROUP
//         - Add is being trapped, but the picker is not being updated yet
//		- knowledge widgets built and embeded
//				- SETUP SCROLLS TO WORK CORRECTLY
//		- BUILD OUT STUBS FOR INITAL SET OF KNOWLEDGE ARTICLES
//    - ADDRESS PAGE JUMPING ISSUE WHEN USER CHANGES TABS
// CREATE SCRIPTS TO RESET TO ROLE
// RUN SCRIPT TO RESET ROLE
// WALK THROUGH PROCESS TO SET UP
// WALK THROUGH AND RECORD PROCESS TO SET UP
// 2.8 | 2022-09-06 | raj  | DFCT0011220 - Add Group modal remains open after clicking on the "Save" button
//																			In Client Script - close modal and pass back id
//
// ******************************************************
(function($sp, input, data, options, gs) {

	var tsss = new tasking_System_Settings_Scripts();
	// NOTE: add option and input for category 
	//       add query to display only properities in category
	//       show all categories or show just provided category
	//  STRY0113883 - reworked code flow
// TODO - MOVE THIS INTO TSS - tsss.DTECH_KNOWLEDGE_BASE_ID = "ddba8256db4d99501e1792c5d496195a"
	// data.kb_sys_id = tsss.DTECH_KNOWLEDGE_BASE_ID;
	data.dtech_knowledged_base_id = "ddba8256db4d99501e1792c5d496195a";

	main();

	function main() {
		if(input){
			_processInput();
		}
		if(!input || !input.loaded){
			 _initialLoad();
			data.loaded = true;
		}
	}

	function _initialLoad(){
		data.category = (input || {}).category || (options || {}).category || $sp.getParameter('category');
		data.showCatecoryHeader = (input || {}).showCatecoryHeader || (options || {}).showCatecoryHeader || $sp.getParameter('showCatecoryHeader');
		data.properties = [];
		// pass category here, or load all
		data.properties = _loadProperties(data.category);
		_buildMessages();		
		_validateAllGroups();
	}

	function _loadProperties(categoryName){
		return tsss.loadCategoryProperties(categoryName);
	}


	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');
		data.submitButtonText = gs.getMessage('Tasker - Button - Save Changes');

		data.addGroupToRoleButtonText = gs.getMessage('Tasker - Button - Add the role now...');
		data.addGroupToRoleToolTip = gs.getMessage('Tasker - Add the role [{0}] to the group [{1}]');

		data.sync = gs.getMessage('Tasker - Sync');
		data.editGroup = gs.getMessage('Tasker - Edit Group');
		data.addGroup = gs.getMessage('Tasker - Add Group');
		data.syncGroup = gs.getMessage('Tasker - Sync Group');
		data.groupMissingRole = gs.getMessage('Tasker - The group is missing the role');
		data.information = gs.getMessage('Tasker - Information');
		data.groupMembers = gs.getMessage('Tasker - Group Members');
		data.showGroupMembersList = gs.getMessage('Tasker - Show group members list');
		data.syncMoveExplicitUsersToGroup = gs.getMessage('Tasker - Move users assigned explicitly to the role into the group.');
		data.explicitRoleUsers = gs.getMessage('Tasker - Has Role Explicitly');
		data.explicitWarningTitle = gs.getMessage('Tasker - Users explicitly assigned to role');
		data.showExplicitRoleUsers = gs.getMessage('Tasker - Show users with role set explicitly');
		data.usersWithExplicitRole = gs.getMessage('Tasker - ({0}) users have the role [{1}] explictly assigned to them');
		data.addUsersToGroupRemoveRole = gs.getMessage('Tasker - Remove the explicit assignment of users with role [{0}] and add the users to the the group [{1}]');
		data.roleMembers = gs.getMessage('Tasker - Role Members');
		data.showRoleMembersList = gs.getMessage('Tasker - Show all role members list');
		data.memberTableRoles = gs.getMessage('Tasker - Member Table Roles');
		data.showMemberTableRolesList = gs.getMessage('Tasker - Show list of Organizational Members with role');
		data.errorGroupNotSelected = gs.getMessage('Tasker - A group is not selected for the role.  Select a group to resolve.');
		data.warningAllGroupsNotSelected = gs.getMessage('Tasker - To enable using groups for roles, a group must be selected for each system role.');
		data.fixIt = gs.getMessage("Tasker - Let's fix it...");
		data.memberTableRoleDescription = gs.getMessage("Tasker - Member Table Role description");
		data.memberTableRoleCompareGroupMembers = gs.getMessage("Tasker - The 'Member Table Role' count does not match the 'Group Members' count.");
		data.memberTableRoleCompareRoleMembers = gs.getMessage("Tasker - The 'Member Table Role' count does not match the 'Role Members' count.");		
		data.syncRoleMembersAndMemberTableRole = gs.getMessage("Tasker - Sync the 'Role Members' with the 'Member Table Role'");
		data.warningAGroupSelectedWarning = gs.getMessage("Tasker - warningAGroupSelectedWarning");
		data.cancelChangesWillBeLost = gs.getMessage("Tasker - Cancelling updates will revert the changes made and reload the previously saved settings.   <br> <br> Would you like to reset to the previous values?")

		data.syncIcon = "Sync24.svg";
		data.warningIcon = "Warning16.svg"
		data.ellipsesIcon = "EllipsesMenu32.svg";
		data.editGroupIcon = "EditGroup24.svg";
		data.addGroupIcon = "AddGroup24.svg";
		data.informationIcon = "Information16_Black.svg"		
		data.groupMembersIcon = "GroupMembers24.svg"
		data.explicitRoleUsersIcon = "RoleMemberExplicitly24.svg"
		data.roleMembersIcon = "RoleMember24.svg"
		data.memberTableRoleIcon = "TableRole24.svg"
		data.errorIcon = "Error16.svg"
	}

	function _processInput(){
		if(input.saveProperties){
			_saveProperties();
		} else if(input.validateGroup){
			_validateGroup();
		} else if(input.validateAllGroups){
			data.properties = input.properties;
			_validateAllGroups();
		} else if(input.addRoleToGroup){
			_addRoleToGroup();
		} else if(input.migrateRoleUsersToGroup){
			_migrateRoleUsersToGrup();
		} else if(input.syncMembersInMemberTableWithRole){
			_syncMembersInMemberTableWithRole();
		} else if(input.syncAll){
			_syncAllGroupRoles();
		} else if(input.getKnowledge){
			_getKnowledgeData(input.groupProperty);
		}
	}

	function _getKnowledgeData (property){

		data.widgetInstanceKBArticles = [];
		data.widgetInstanceKBRelatedArticles = [];
		if(property.KBArticle){
			var widget_name = "tasker-kb-article-content";
			var widget_parameters = { 
				knowledge_base: data.dtech_knowledged_base_id,
				sysparm_article: property.KBArticle
			};
			var widgetInstanceKBArticles = $sp.getWidget(widget_name, widget_parameters);
			data.widgetInstanceKBArticles.push(widgetInstanceKBArticles);

			widget_name = "tasker_knowledge_list_widget_template";
			widget_parameters = { 
				knowledge_base: data.dtech_knowledged_base_id,
				sysparm_article: property.KBArticle
			};
			var widgetInstanceKBRelatedArticles = $sp.getWidget(widget_name, widget_parameters);
			data.widgetInstanceKBRelatedArticles.push(widgetInstanceKBRelatedArticles);			
		}
	}

	function _validateAllGroups(){
		data.properties = tsss.validateAllGroups(data.properties);
	}

	function _validateGroup(){
		input.groupProperty = tsss.validateGroupRole(input.groupProperty);
		data.replaceProperty = input.groupProperty;
	}

	function _saveProperties(){
		tsss.saveProperties(input.properties);
	}

	function _addRoleToGroup(){
		// TODO - add error handling in server script
		//        remove post to form and add error to property
		//        update html to post message to screen in group area
		// add role to group and set return value
		data.roleAddedToGroup = tsss.addRoleToGroup(input.groupProperty);
		if(data.roleAddedToGroup){
			gs.addInfoMessage(gs.getMessage("Role: [{0}] was added to Group: [{1}]",[input.groupProperty.roleName, input.groupProperty.value.displayValue ]))
		} else {
			gs.addErrorMessage(gs.getMessage("Role: [{0}] was not added to Group: [{1}]",[input.groupProperty.roleName, input.groupProperty.value.displayValue ]))
		}
	}

	function _syncMembersInMemberTableWithRole(){
		// call script include to process sync
		tsss.syncMembersInMemberTableWithRole(input.groupProperty);
		// run validation again, it will set the property to pass back
		_validateGroup();
	}

	function _syncAllGroupRoles(){
	 data.properties = tsss.syncAllGroupRoles(input.properties);
		_validateAllGroups();
	}

	function _migrateRoleUsersToGrup(){
		// TODO - add error handling in server script
		//        remove post to form and add error and success to property
		//        update html to post message to screen in group area
		// migrate users form role to group and set return value
		data.roleAUsersAdded = tsss.migrateRoleUsersIntoGroup(input.groupProperty);
		if(data.roleAUsersAdded >= 0){
			gs.addInfoMessage(gs.getMessage("Role: [{0}] migrated [{1}] users to Group: [{2}]",[input.groupProperty.roleName, data.roleAUsersAdded, input.groupProperty.value.displayValue ]))
		} else {
			gs.addErrorMessage(gs.getMessage("Error migrating users from Role: [{0}] to Group: [{1}]",[input.groupProperty.roleName, input.groupProperty.value.displayValue ]))
		}
	}	
})($sp, input, data, options, gs);
